from dataclasses import dataclass, field
from typing import Optional, List


@dataclass
class Grade:
    subject: str
    score: float


class Student:
    GRADE_THRESHOLDS = [(90, 'A'), (80, 'B'), (70, 'C'), (60, 'D')]

    def __init__(self, name: str):
        self.name = name
        self.grades: List[Grade] = []
        self.attendance: int = 0
        self.total_classes: int = 0

    def add_grade(self, subject: str, score: float) -> bool:
        if not 0 <= score <= 100:
            return False
        self.grades.append(Grade(subject, score))
        return True

    @property
    def average(self) -> float:
        if not self.grades:
            return 0.0
        return sum(g.score for g in self.grades) / len(self.grades)

    @property
    def letter_grade(self) -> str:
        avg = self.average
        for threshold, letter in self.GRADE_THRESHOLDS:
            if avg >= threshold:
                return letter
        return 'F'

    def record_attendance(self, present: bool) -> None:
        self.total_classes += 1
        if present:
            self.attendance += 1

    @property
    def attendance_rate(self) -> float:
        if self.total_classes == 0:
            return 0.0
        return self.attendance / self.total_classes

    def get_report(self) -> dict:
        return {
            'name': self.name,
            'average': self.average,
            'letter_grade': self.letter_grade,
            'attendance_rate': self.attendance_rate,
            'total_grades': len(self.grades),
        }


class GradeBook:
    def __init__(self):
        self._students: dict[str, Student] = {}

    def add_student(self, name: str) -> bool:
        if name in self._students:
            return False
        self._students[name] = Student(name)
        return True

    def get_student(self, name: str) -> Optional[Student]:
        return self._students.get(name)

    def add_grade(self, name: str, subject: str, score: float) -> bool:
        student = self.get_student(name)
        if student is None:
            return False
        return student.add_grade(subject, score)

    def get_average(self, name: str) -> float:
        student = self.get_student(name)
        if student is None:
            return -1
        return student.average

    def get_letter_grade(self, name: str) -> str:
        student = self.get_student(name)
        if student is None:
            return 'N/A'
        return student.letter_grade
